export const SUPPORTED_LOCALES = ['en', 'ko', 'ru', 'hi', 'ta'] as const
export type SupportedLocale = typeof SUPPORTED_LOCALES[number]

export const APP_LOCALE_OPTIONS = ['system', ...SUPPORTED_LOCALES] as const
export type AppLocale = typeof APP_LOCALE_OPTIONS[number]

export const DEFAULT_LOCALE: SupportedLocale = 'en'

export const localeLabels: Record<AppLocale, string> = {
  system: 'System Default',
  en: 'English',
  ko: '한국어',
  ru: 'Русский',
  hi: 'हिन्दी',
  ta: 'தமிழ்',
}

export function isAppLocale(value: unknown): value is AppLocale {
  return typeof value === 'string' && (APP_LOCALE_OPTIONS as readonly string[]).includes(value)
}

export function normalizeSupportedLocale(locale: string | null | undefined): SupportedLocale {
  if (!locale) return DEFAULT_LOCALE
  const normalized = locale.toLowerCase()
  const base = normalized.split(/[-_]/)[0]

  switch (base) {
    case 'ko':
    case 'ru':
    case 'hi':
    case 'ta':
      return base
    default:
      return DEFAULT_LOCALE
  }
}

export function resolveAppLocale(locale: AppLocale | null | undefined, systemLocale: string | null | undefined): SupportedLocale {
  if (!locale || locale === 'system') {
    return normalizeSupportedLocale(systemLocale)
  }

  return normalizeSupportedLocale(locale)
}

